class Solution {
    public int shortestMatchingSubstring(String s, String p) {
        int firstStar = p.indexOf('*');
        int secondStar = p.indexOf('*', firstStar + 1);
        String prefix = p.substring(0, firstStar);
        String middle = p.substring(firstStar + 1, secondStar);
        String suffix = p.substring(secondStar + 1);

        int minLen = Integer.MAX_VALUE;
        int n = s.length();

        for (int i = 0; i <= n; i++) {
            int prefixEnd = i + prefix.length();
            if (prefixEnd > n) break;
            if (!s.substring(i, prefixEnd).equals(prefix)) continue;

            for (int j = prefixEnd; j <= n; j++) {
                int middleEnd = j + middle.length();
                if (middleEnd > n) break;
                if (!s.substring(j, middleEnd).equals(middle)) continue;

                int suffixStart = middleEnd;
                int suffixEnd = suffixStart + suffix.length();
                while (suffixEnd <= n) {
                    if (s.substring(suffixStart, suffixEnd).equals(suffix)) {
                        int len = suffixEnd - i;
                        if (len < minLen) minLen = len;
                        break;
                    }
                    suffixStart++;
                    suffixEnd++;
                }
            }
        }

        return minLen == Integer.MAX_VALUE ? -1 : minLen;
    }
}
